#SETP_0.1:alter_system
#OBS接受到用户发起的bootstarp命令，语法格式为:ALTER SYSTEM BOOTSTRAP ZONE='ZONE1'
SERVER='10.232.144.13:2209', ZONE='zone2' SERVER='10.244.4.14:2203'
#SETP_0.2:boot_strap_rpc
#SQL端处理命令，向接受alter system命令的obsesrver发起bootstrap RPC命令，传入参数 rs_list; RPC_S(PR5
    bootstrap, OB_BOOTSTRAP, (ObServerInfoList));
#SETP_1:obs收到bootstrap的rpc命令，开始prepare_bootstrap操作：
STEP_1.1:check_bootstrap_rs_list
检查rs_list里面指定的SERVER地址，不能出现两个SERVER位于同一个ZONE中的情况；因为每个ZONE里面只有一个副本；
STEP_1.2:check_is_all_server_empty
给RS_LIST里面的每个RS发送RPC，询问该SERVER的状态是否为初始状态，不包含任何数据; RPC_S(PR5
    is_empty_server, OB_IS_EMPTY_SERVER, Bool);
STEP_1.3:create_partition
创建__all_core_table的partition.
为了加快选主进度，会直接指定rs_list中第一个obs为主partition,这里采用的异步RPC要求rs_list里面的rs创建__all_core_table；
STEP_1.4:wait_elect_master_partition
检查partition service里面的状态，确认__all_core_table的主已经选出来了。
STEP_1.5:prepare_bootstrap
至此，prepare的工作已经做完了。prepare的工作主要就是检查所有server的状态为空，创建出__all_core_table，并选出主partition来，主partition所在的RS就是主RS。下一步就是往主RS发送execute_bootstrap的RPC命令了。
STEP_2.1:check_is_already_bootstrap
检查当前schema版本，确认没有处于bootstrap过程中；
STEP_2.2:check_bootstrap_rs_list
重复检查rs_listl里面没有属于同一个zone的RS；
STEP_2.3:add_rs_list
将RS加入到server_manager里面；
STEP_2.4:wait_all_rs_online
等待所有RS的状态都是active；
STEP_2.5:init_global_stat
初始化core_schema_version.这里会往__all_core_table里面写入三行数据。inner
sql会发给__all_core_table所在的主；
INSERT INTO __all_core_table (table_name, row_id, column_name, column_value, gmt_create,
    gmt_modified) VALUES ('__all_global_stat', 0, 'core_schema_version', '1',
      usec_to_time(1472534133389119), usec_to_time(1472534133389119));
INSERT INTO __all_core_table (table_name, row_id, column_name, column_value, gmt_create,
    gmt_modified) VALUES ('__all_global_stat', 0, 'try_frozen_version', '1',
      usec_to_time(1472534133389119), usec_to_time(1472534133389119));
INSERT INTO __all_core_table (table_name, row_id, column_name, column_value, gmt_create,
    gmt_modified) VALUES ('__all_global_stat', 0, 'frozen_version', '1',
      usec_to_time(1472534133389119), usec_to_time(1472534133389119));
STEP_2.6:construct_all_schema
生成所有表的schema.表的类型包括：核心表，系统表，虚拟表，视图。这些表的schema是通过脚本文件直接生成的；
STEP_2.7:broadcast_sys_schema
将第六步生成的schema RPC 广播给所有的RS; 收到命令的RS会用这个schema来初始化schame_cache;
RPC_S(PR5 broadcast_sys_schema, OB_BROADCAST_SYS_SCHEMA,
    (common::ObSArray<share::schema::ObTableSchema>));
STEP_2.8:create_all_partitions
收集核心表和系统表的信息，统一调用 ObPartitionCreator.execute接口，统一创建所有partition.
然后等待这些partition的主选出
STEP_2.9:create_all_schema
将所有表的schema写入到内部表中，其中区分核心表和非核心表。核心表的schame写入到__all_core_table中，非核心表的schema写入到__all_table和__all_column表里面；
STEP_2.10:create_sys_unit_config
创建系统unit config
STEP_2.11:create_sys_resource_pool
创建系统resource pool;
STEP_2.12:create_sys_tenant
创建sys租户；同时初始化该tenant的一些属性，产生多条内部SQL:
REPLACE INTO __all_tenant (tenant_id, tenant_name, replica_num, locked, zone_list, primary_zone,
info, collation_type, read_only, rewrite_merge_version, gmt_modified) VALUES (1, X'737973', 1,
0, 'zone1', 'zone1', 'system tenant', 45, 0, 0, now(6))")
往__all_tablegroup表中插入sys tablegroup的行；
创建租户的五大database： oceanbase/mysql/information_schema/recyclebin/test
权限信息写入了__ALL_DATABASE_PRIVILEGE; 系统用户拥有全部的权限；
新建该tenant的root用户； 插入数据到__all_user/__all_user_history/__all_ddl_operation
初始化__al_sys_variable表；把所有系统变量写入表中；
初始化__all_sys_stat表.如果是系统租户的话，写入：ob_max_used_tenant_id.ob_max_used_unit_config_id_/ob_max_used_server_id_、ob_max_used_unit_id_等。
如果是普通用户的话，写入：ob_max_used_database_id_、ob_max_used_tablegroup_id、ob_max_used_sequence_id等等
初始化__all_charset, 字符集表
初始化__all_collation，collation表
初始化__all_privilege，权限信息表
STEP_2.13:init_server_id
更新__all_sys_stat表中最大的server_id;产生一条内部SQL：
UPDATE __all_sys_stat SET VALUE = '1', gmt_modified = now(6) WHERE ZONE = '' AND NAME =
'ob_max_used_server_id' AND TENANT_ID = 1"
STEP_2.14:init_all_zone_table
初始化__all_zone表。 会产生一些列的插入操作；比如：
INSERT INTO __all_zone (zone, name, value, info, gmt_modified) VALUES('', 'merge_status', 0, 'IDLE',
    now(6))，不指定zone的语句用来修改>全局的状态信息；
比如：
INSERT INTO __all_zone (zone, name, value, info, gmt_modified) VALUES('zone1', 'status', 2,
'ACTIVE', now(6)) 指定zone的语句用来修改特定zone的状态信息；
STEP_2.16:wait_all_rs_in_service
所有内部表操作结束，等待RS的状态都切换成in service;
STEP_2.17:execute_bootstrap
BOOTSTRAP阶段的工作已经做完。接下来就是RS的一些任务线程的启动；
